define float @fadd_sel_op0(i1 %b, float %x) {
  %s = select i1 %b, float 0xFFF0000000000000, float 0x7FF0000000000000
  %r = fadd nnan float %s, %x
  ret float %r
}

define float @fmul_select(float %x, i1 %c) {
  %sel = select i1 %c, float 1.000000e+00, float 0.000000e+00
  %mul = fmul fast float %sel, %x
  ret float %mul
}

define <2 x float> @fmul_select_vec(<2 x float> %x, i1 %c) {
  %sel = select i1 %c, <2 x float> <float 1.000000e+00, float 1.000000e+00>, <2 x float> zeroinitializer
  %mul = fmul fast <2 x float> %sel, %x
  ret <2 x float> %mul
}

define <2 x double> @negate_if_true_wrong_constant(<2 x double> %px, i1 %cond) {
  %x = fdiv <2 x double> <double 4.200000e+01, double 4.200000e+01>, %px
  %sel = select i1 %cond, <2 x double> <double -1.000000e+00, double 0.000000e+00>, <2 x double> <double 1.000000e+00, double 1.000000e+00>
  %r = fmul <2 x double> %x, %sel
  ret <2 x double> %r
}

define i32 @basic(i32 %a, i32 %b) {
  %cmp = icmp eq i32 %a, 0
  %sel = select i1 %cmp, i32 %b, i32 0
  %or = or i32 %sel, %a
  ret i32 %or
}

define i32 @cmp_swapped(i32 %x, i32 %y) {
  %cmp = icmp eq i32 0, %x
  %sel = select i1 %cmp, i32 %y, i32 0
  %or = or i32 %x, %sel
  ret i32 %or
}

define i32 @negative_non_zero_false_val(i32 %a, i32 %b) {
  %cmp = icmp eq i32 %a, 0
  %sel = select i1 %cmp, i32 %b, i32 1
  %or = or i32 %sel, %a
  ret i32 %or
}

define i32 @negative_wrong_predicate(i32 %a, i32 %b) {
  %cmp = icmp ne i32 %a, 0
  %sel = select i1 %cmp, i32 %b, i32 0
  %or = or i32 %sel, %a
  ret i32 %or
}

define i32 @swap_operand_order(i32 %x, i32 %y) {
  %cmp = icmp eq i32 %x, 0
  %sel = select i1 %cmp, i32 %y, i32 0
  %or = or i32 %x, %sel
  ret i32 %or
}

define <2 x i32> @vector_type(<2 x i32> %a, <2 x i32> %b) {
  %cmp = icmp eq <2 x i32> %a, zeroinitializer
  %sel = select <2 x i1> %cmp, <2 x i32> %b, <2 x i32> zeroinitializer
  %or = or <2 x i32> %sel, %a
  ret <2 x i32> %or
}
